mapper.select:
SELECT s.id As id, s.buy_contract_id As buyContractId, s.buy_product_id As buyProductId, s.product_name As productName, s.product_cd As productCd, s.brand_number As brandNumber, s.factory_id As factoryId, s.factory_name As factoryName, s.warehouse_id As warehouseId, s.warehouse_name As warehouseName, s.deal_price As dealPrice, s.warehouse_amount As warehouseAmount, s.buy_number As buyNumber, s.selling_number As sellingNumber, s.sell_number As sellNumber, s.presell_number As presellNumber, s.delivery_in_number As deliveryInNumber, s.delivery_out_number As deliveryOutNumber, s.enterprise_id As enterprise_id, s.biz_user_id As bizUserId, s.biz_user_name As bizUserName, c.contract_no As contractNo, DATEDIFF(IFNULL(c.contract_end_time,Now()),c.contract_time) AS contractDifTime FROM t_stock_contract s LEFT JOIN t_ctr_contract c ON s.buy_contract_id = c.id WHERE s.enterprise_id = #{enterpriseId}
AND c.contract_no LIKE CONCAT('%',#{contractNo},'%')
ORDER BY s.created_date DESC
